${pagingTop}
SELECT 
	HOMEPAGE_ID, LOCKER_IDX, LOCKER_NAME, LOCKER_DESC, 
	STATUS, ADD_DATE, ADD_ID, MOD_DATE, MOD_ID, LOCKER_PRE_IDX
FROM 
	LOCKER
WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND LOCKER_PRE_IDX = #{locker_pre_idx}

		AND LOCKER_NAME LIKE '%'||#{search_text}||'%'


		AND STATUS = #{status}

ORDER BY 
	LOCKER_IDX DESC
${pagingBottom}

SELECT A.HOMEPAGE_ID, A.LOCKER_IDX, A.LOCKER_NAME, A.LOCKER_DESC, A.STATUS, A.ADD_DATE, A.ADD_ID, A.MOD_DATE, A.MOD_ID, A.LOCKER_PRE_IDX, B.APPLY_ID, B.REQ_NAME, B.REQ_IDX, B.MEMBER_KEY FROM LOCKER A LEFT OUTER JOIN LOCKER_REQ B ON A.LOCKER_IDX = B.LOCKER_IDX AND A.HOMEPAGE_ID = B.HOMEPAGE_ID AND A.LOCKER_PRE_IDX = B.LOCKER_PRE_IDX AND B.DELETE_YN = 'N'
WHERE A.HOMEPAGE_ID = #{homepage_id} AND A.DELETE_YN = 'N' AND A.LOCKER_PRE_IDX = #{locker_pre_idx}
AND A.LOCKER_NAME LIKE '%'||#{search_text}||'%'
AND A.STATUS = #{status}
ORDER BY A.LOCKER_IDX

SELECT COUNT(*) FROM LOCKER WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND LOCKER_PRE_IDX = #{locker_pre_idx}
AND LOCKER_NAME LIKE '%'||#{search_text}||'%'
AND STATUS = #{status}
ORDER BY LOCKER_IDX DESC

